import React from "react"
import { PageTitle } from '@/components/ui/Typography';
import { PageCard } from "@/components/PageCard"
import { Button, Alert, Box, Typography } from "@mui/material"
import { StatusMessage } from "@/components/StatusMessage"
import RestartAltIcon from '@mui/icons-material/RestartAlt';
import { CallStatus } from "@/types/api.types";
import { DateTimeReadable } from "@/utils/common";
import { getApiError } from "@/utils/apiError";
import { useNavigate } from '@tanstack/react-router';
import { AuthServices, AuthServicesError } from "@/api";

export const ResetAuth: React.FC = () => {
    const [authReset, setAuthReset] = React.useState<CallStatus>(CallStatus.NotStarted);
    const [resetTimestamp, setResetTimestamp] = React.useState<Date | null>(null);
    const [correlationId, setCorrelationId] = React.useState<string | undefined>(undefined);
    const [httpStatus, setHttpStatus] = React.useState<number>(0);

    const navigate = useNavigate();

    const handleResetAuth = () => {
        setAuthReset(CallStatus.InProgress);
        setCorrelationId(undefined);
        setHttpStatus(0);
        AuthServices.ResetMine()
            .then((res: { data?: { status?: number } }) => {
                if ((res?.data?.status ?? 0) >= 200 && (res?.data?.status ?? 0) < 300) {
                    setAuthReset(CallStatus.Success);
                    setResetTimestamp(new Date());
                    navigate({ to: '/expired' });
                } else {
                    setAuthReset(CallStatus.Failure);
                    setResetTimestamp(null);
                    setHttpStatus(res?.data?.status ?? 0);
                }
            })
            .catch((err) => {
                setAuthReset(CallStatus.Failure);
                setResetTimestamp(null);
                const apiErr = getApiError(err);
                setHttpStatus(apiErr.httpStatus);
                setCorrelationId(apiErr.correlationId);
            });
    }

    return (
        <>
            <PageCard>
                <PageTitle>Reset Authentication</PageTitle>
                <Typography variant="body1">This option is to reset your authentication. After performing this action, you will be logged-out from all the devices. You will need to freshly login or freshly setup your offline OTP generation on Google Authenticator/ Microsoft Authenticator.</Typography>
                <Box sx={{ mt: 2, display: 'flex', justifyContent: 'flex-end' }}>
                    <Button variant="contained" endIcon={<RestartAltIcon />} onClick={handleResetAuth}>
                        Reset
                    </Button>
                </Box>
                <Box sx={{ mt: 2 }}><Alert severity="warning">After RESET, You need to login again and setup authenticator again!</Alert></Box>
                <StatusMessage
                    currentStatus={authReset}
                    successMessage={resetTimestamp ? `Successfully reset at ${DateTimeReadable(resetTimestamp)}` : "Successfully reset."}
                    failureMessage={AuthServicesError.ResetAuthError(httpStatus)}
                    correlationId={correlationId}
                />
            </PageCard>
        </>
    )
}
